     6→namespace Envoy {
     7→namespace Config {
     8→
     9→/**
    10→ * This class arbitrates between two config providers of the same GrpcMux -
    11→ * the primary and the failover. Envoy always prefers fetching config from the
    12→ * primary source, but if not available, it will fetch the config from the failover
    13→ * source until the primary is again available.
    14→ *
    15→ * This class owns the state for the GrpcMux primary and failover streams, and
    16→ * proxies the gRPC-stream functionality to either the primary or the failover config sources.
    17→ * The failover source is optional and will only be used if given in the c'tor.
    18→ *
    19→ * Failover is supported in both
    20→ * SotW (RequestType = envoy::service::discovery::v3::DiscoveryRequest,
    21→ *   ResponseType = envoy::service::discovery::v3::DiscoveryResponse), and
    22→ * Delta-xDS (RequestType = envoy::service::discovery::v3::DeltaDiscoveryRequest,
    23→ *   ResponseType = envoy::service::discovery::v3::DeltaDiscoveryResponse).
    24→ * Both the primary and failover streams are either SotW or Delta-xDS.
    25→ *
    26→ * The use of this class will be as follows: the GrpcMux object will own an instance of
    27→ * the GrpcMuxFailover. The GrpcMuxFailover will own 2 GrpcStreams, primary and failover.
    28→ * Each of the primary and secondary streams will invoke GrpcStreamCallbacks
    29→ * on their corresponding objects (also owned by the GrpcMuxFailover). These invocations
    30→ * will be followed by the GrpcMuxFailover calling the GrpcStreamCallbacks on the GrpcMux
    31→ * object that initialized it.
    32→ *
    33→ * Note: this class is WIP and should be considered alpha!
    34→ * At the moment, the supported policy is as follows:
    35→ * The GrpcMuxFailover attempts to establish a connection to the primary source. Once a response is
    36→ * received from the primary source it will be considered available, and the failover will not be
    37→ * used. Any future reconnection attempts will be to the primary source only.
    38→ * However, if no response is received from the primary source, and accessing the primary has
    39→ * failed 2 times in a row, the GrpcMuxFailover will attempt to establish a connection to the
    40→ * failover source. If a response from the failover source is received, only the failover source
    41→ * will be used.
    42→ * If the failover source is unavailable, the GrpcMuxFailover will alternate between attempts
    43→ * to reconnect to the primary source and the failover source.
    44→ * In the future, this behavior may change, and the GrpcMuxFailover will always
    45→ * prefer the primary source, even if prior connection to the failover was successful.
    46→ * TODO(adisuissa): The number of consecutive failures is currently statically
    47→ * defined, and may be converted to a config field in the future.
    48→ */
    49→template <class RequestType, class ResponseType>
    50→class GrpcMuxFailover : public GrpcStreamInterface<RequestType, ResponseType>,
    51→                        public Logger::Loggable<Logger::Id::config> {
    52→public:
    53→  static constexpr uint32_t DefaultFailoverBackoffMilliseconds = 500;
    54→
    55→  // A GrpcStream creator function that receives the stream callbacks and returns a
    56→  // GrpcStream object. This is introduced to facilitate dependency injection for
    57→  // testing and will be used to create the primary and failover streams.
    58→  using GrpcStreamCreator = std::function<GrpcStreamInterfacePtr<RequestType, ResponseType>(
    59→      GrpcStreamCallbacks<ResponseType>* stream_callbacks)>;
    60→
    61→  GrpcMuxFailover(GrpcStreamCreator primary_stream_creator,
    62→                  absl::optional<GrpcStreamCreator> failover_stream_creator,
    63→                  GrpcStreamCallbacks<ResponseType>& grpc_mux_callbacks,
    64→                  Event::Dispatcher& dispatcher)
    65→      : grpc_mux_callbacks_(grpc_mux_callbacks), primary_callbacks_(*this),
    66→        primary_grpc_stream_(std::move(primary_stream_creator(&primary_callbacks_))),
    67→        connecting_to_primary_(false), connecting_to_failover_(false),
    68→        connected_to_(ConnectedState::None), ever_connected_to_(ConnectedState::None) {
    69→    ASSERT(primary_grpc_stream_ != nullptr);
    70→    if (failover_stream_creator.has_value()) {
    71→      ENVOY_LOG(warn, "Using xDS-Failover. Note that the implementation is currently considered "
    72→                      "experimental and may be modified in future Envoy versions!");
    73→      // Only create the retry timer if failover is supported.
    74→      complete_retry_timer_ = dispatcher.createTimer([this]() -> void { retryConnections(); });
    75→      failover_callbacks_ = std::make_unique<FailoverGrpcStreamCallbacks>(*this);
    76→      GrpcStreamCreator& failover_stream_creator_ref = failover_stream_creator.value();
    77→      failover_grpc_stream_ = std::move(failover_stream_creator_ref(failover_callbacks_.get()));
    78→      ASSERT(failover_grpc_stream_ != nullptr);
    79→    }
    80→  }
    81→
    82→  virtual ~GrpcMuxFailover() = default;
    83→
    84→  // Attempts to establish a new stream to the either the primary or failover source.
    85→  void establishNewStream() override {
    86→    // Attempt establishing a connection to the primary source.
    87→    // This method may be called multiple times, even if the primary stream is already
    88→    // established or in the process of being established.
    89→    if (complete_retry_timer_) {
    90→      complete_retry_timer_->disableTimer();
    91→    }
    92→    // First check if Envoy ever connected to the primary/failover, and if so
    93→    // persist attempts to that source.
    94→    if (ever_connected_to_ == ConnectedState::Primary) {
    95→      ASSERT(!connecting_to_failover_);
    96→      ENVOY_LOG_MISC(trace, "Attempting to reconnect to the primary gRPC source, as a connection "
    97→                            "to it was previously established.");
    98→      establishStreamToPrimaryIfNotConnected();
    99→      return;
   100→    } else if (ever_connected_to_ == ConnectedState::Failover) {
   101→      ASSERT(!connecting_to_primary_);
   102→      ENVOY_LOG_MISC(trace, "Attempting to reconnect to the failover gRPC source, as a connection "
   103→                            "to it was previously established.");
   104→      establishStreamToFailoverIfNotConnected();
   105→      return;
   106→    }
   107→    // No prior connection was established, prefer the primary over the failover.
   108→    if (connecting_to_failover_) {
   109→      establishStreamToFailoverIfNotConnected();
   110→    } else {
   111→      // Either connecting to primary or connected to it, or neither.
   112→      establishStreamToPrimaryIfNotConnected();
   113→    }
   114→  }
   115→
   116→  // Returns the availability of the underlying stream.
   117→  bool grpcStreamAvailable() const override {
   118→    if (connectingToOrConnectedToFailover()) {
   119→      return failover_grpc_stream_->grpcStreamAvailable();
   120→    }
   121→    // Either connecting/connected to the primary, or no connection was attempted.
   122→    return primary_grpc_stream_->grpcStreamAvailable();
   123→  }
   124→
   125→  // Sends a message using the underlying stream.
   126→  void sendMessage(const RequestType& request) override {
   127→    if (connectingToOrConnectedToFailover()) {
   128→      failover_grpc_stream_->sendMessage(request);
   129→      return;
   130→    }
   131→    // Either connecting/connected to the primary, or no connection was attempted.
   132→    primary_grpc_stream_->sendMessage(request);
   133→  }
   134→
   135→  // Updates the queue size of the underlying stream.
   136→  void maybeUpdateQueueSizeStat(uint64_t size) override {
   137→    if (connectingToOrConnectedToFailover()) {
   138→      failover_grpc_stream_->maybeUpdateQueueSizeStat(size);
   139→      return;
   140→    }
   141→    // Either connecting/connected to the primary, or no connection was attempted.
   142→    primary_grpc_stream_->maybeUpdateQueueSizeStat(size);
   143→  }
   144→
   145→  // Returns true if the rate-limit allows draining.
   146→  bool checkRateLimitAllowsDrain() override {
   147→    if (connectingToOrConnectedToFailover()) {
   148→      return failover_grpc_stream_->checkRateLimitAllowsDrain();
   149→    }
   150→    // Either connecting/connected to the primary, or no connection was attempted.
   151→    return primary_grpc_stream_->checkRateLimitAllowsDrain();
   152→  }
   153→
   154→  // Returns the close status for testing purposes only.
   155→  absl::optional<Grpc::Status::GrpcStatus> getCloseStatusForTest() {
   156→    if (connectingToOrConnectedToFailover()) {
   157→      return failover_grpc_stream_->getCloseStatusForTest();
   158→    }
   159→    ASSERT(connectingToOrConnectedToPrimary());
   160→    return primary_grpc_stream_->getCloseStatusForTest();
   161→  }
   162→
   163→  // Returns the current stream for testing purposes only.
   164→  GrpcStreamInterface<RequestType, ResponseType>& currentStreamForTest() {
   165→    if (connectingToOrConnectedToFailover()) {
   166→      return *failover_grpc_stream_;
   167→    }
   168→    ASSERT(connectingToOrConnectedToPrimary());
   169→    return *primary_grpc_stream_;
   170→  };
   171→
   172→  // Retries to connect again to the primary and then (possibly) to the
   173→  // failover. Assumes that no connection has been made or is being attempted.
   174→  void retryConnections() {
   175→    ASSERT(!connecting_to_primary_ && !connecting_to_failover_ &&
   176→           (connected_to_ == ConnectedState::None));
   177→    ENVOY_LOG(trace, "Expired timer, retrying to reconnect to the primary xDS server.");
   178→    connecting_to_primary_ = true;
   179→    primary_grpc_stream_->establishNewStream();
   180→  }
